import React, { useState } from "react";
import TestimonialCard from "./TestimonialCard";
import { motion } from "framer-motion";

const cardsData = [
  {
    title: "Frontend",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "list",
    backContent: [
      "Octavio Luna",
      "Leonardo Ibarra",
      "Leandro Colque",
      "Rodny Siles",
      "Kevin Sancalli",
      "Einar Guillen",
      "Huascar Duran",
      "Alejandro Zamorano",
    ],
  },
  {
    title: "Backend",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "list",
    backContent: [
      "Octavio Luna",
      "Leonardo Ibarra",
      "Leandro Colque",
      "Rodny Siles",
      "Kevin Sancalli",
      "Einar Guillen",
      "Huascar Duran",
      "Alejandro Zamorano",
    ],
  },
  {
    title: "Base de datos",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "list",
    backContent: [
      "Octavio Luna",
      "Leonardo Ibarra",
      "Leandro Colque",
      "Rodny Siles",
      "Kevin Sancalli",
      "Einar Guillen",
      "Huascar Duran",
      "Alejandro Zamorano",
    ],
  },
  {
    title: "Dashboard",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "list",
    backContent: [
      "Octavio Luna",
      "Leonardo Ibarra",
      "Leandro Colque",
      "Rodny Siles",
      "Kevin Sancalli",
      "Einar Guillen",
      "Huascar Duran",
      "Alejandro Zamorano",
    ],
  },
  {
    title: "Daniela Carolina Ovando Santander",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "image",
    backContent: "/ruta/a/la/imagen1.jpg",
  },
  {
    title: "Jessica",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "image",
    backContent: "/ruta/a/la/imagen2.jpg",
  },
  {
    title: "Guido",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "image",
    backContent: "/ruta/a/la/imagen3.jpg",
  },
];

const PersonalSection = () => {
  const [index, setIndex] = useState(0);

  const visibleCards = cardsData.slice(index, index + 4);

  const handleNext = () => {
    if (index + 4 < cardsData.length) setIndex(index + 1);
  };

  const handlePrev = () => {
    if (index > 0) setIndex(index - 1);
  };

  return (
    <section style={{ textAlign: "center", padding: "1rem" }}>
      <h2
        style={{
          fontSize: "2rem",
          fontWeight: "bold",
          color: "black",
          marginBottom: "2rem",
        }}
      >
        LAS PERSONAS Y EQUIPOS QUE HICIERON POSIBLE TODO ESTO
      </h2>

      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          gap: "0.5rem",
          flexWrap: "nowrap",
          overflow: "hidden",
          maxWidth: "1300px",
          margin: "0 auto",
          padding: "0 0.5rem",
        }}
      >
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handlePrev}
          style={{
            backgroundColor: "#154734",
            color: "#e4d0a9",
            width: 45,
            height: 45,
            borderRadius: "50%",
            fontSize: "1.7rem",
            border: "none",
            cursor: "pointer",
            userSelect: "none",
            flexShrink: 0,
            marginRight: 5,
          }}
          disabled={index === 0}
        >
          ◀
        </motion.button>

        <div
          style={{
            display: "flex",
            gap: "0.5rem",
            overflow: "hidden",
            flexGrow: 1,
            justifyContent: "center",
          }}
        >
          {visibleCards.map((card, i) => (
            <TestimonialCard key={index + i} card={card} />
          ))}
        </div>

        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handleNext}
          style={{
            backgroundColor: "#154734",
            color: "#e4d0a9",
            width: 45,
            height: 45,
            borderRadius: "50%",
            fontSize: "1.7rem",
            border: "none",
            cursor: "pointer",
            userSelect: "none",
            flexShrink: 0,
            marginLeft: 5,
          }}
          disabled={index + 4 >= cardsData.length}
        >
          ▶
        </motion.button>
      </div>
    </section>
  );
};

export default PersonalSection;
